-- ============================================================
-- game-developer-roadmap-sh-full-detailed-seed-v1.sql
-- Full detailed Game Developer roadmap seed based on roadmap.sh/game-developer.
-- Idempotent seed: safe to rerun in the same database/session.
-- ============================================================

-- Shared-skill aliases normalized against core/shared-skills.seed.sql.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

DELETE FROM public.progress_event WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('Game Developer Roadmap', 'Game Developer Roadmap - roadmap.sh Full Detailed Seed', 'Game Development Roadmap Full Detailed Seed'));
DELETE FROM public.user_node_progress WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('Game Developer Roadmap', 'Game Developer Roadmap - roadmap.sh Full Detailed Seed', 'Game Development Roadmap Full Detailed Seed'));
DELETE FROM public.roadmap_enrollment WHERE roadmap_version_id IN (SELECT rv.roadmap_version_id FROM public.roadmap_version rv JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('Game Developer Roadmap', 'Game Developer Roadmap - roadmap.sh Full Detailed Seed', 'Game Development Roadmap Full Detailed Seed'));
DELETE FROM public.roadmap WHERE title IN ('Game Developer Roadmap', 'Game Developer Roadmap - roadmap.sh Full Detailed Seed', 'Game Development Roadmap Full Detailed Seed');

    'Game Developer',
    'game-developer',
    'Game developer path covering programming, engines, game math, physics, graphics, gameplay systems, UI, audio, AI, multiplayer, optimization, publishing, and portfolio-ready production.',
    'Game Development',
    true
) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, category = EXCLUDED.category, is_active = true, updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (SELECT career_role_id FROM public.career_role WHERE slug = 'game-developer'), inserted_roadmap AS (
    SELECT career_role_id, 'Game Developer Roadmap', 'A structured learning path for becoming a game developer, covering game programming, engines, math, physics, graphics, gameplay systems, UI, audio, AI, multiplayer, optimization, publishing, and portfolio-ready production.', 'template', 'static', 'public' FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
    SELECT roadmap_id, 1, 'published', 'Game Developer Roadmap v1', 'A practical game development roadmap that moves from foundations to shippable portfolio work through engine skills, guided topics, checkpoints, optional practice projects, and required milestone projects.', 420, 'none', '{}'::jsonb, 'TB', 'custom', now() FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
) SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;






