('final-game-developer-review', 'portfolio-and-career-readiness', 'checkpoint', 'review', NULL, NULL, 'Final Game Developer Review', 'Final roadmap checkpoint for Portfolio and Career Readiness. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the game development path.', 'This checkpoint closes the suggested game development orientation path by organizing evidence and next steps. It is not an employment guarantee or formal competency certification.', 238, 'checkpoint', 'portfolio-and-career-readiness', 1202, 7, 2, 'intermediate', 12, '{"source": "roadmap.sh/game-developer", "parentGroup": "portfolio-and-career-readiness", "checkpointPurpose": "phase_review", "reviewMode": "final_review", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Connect completed roadmap work to a coherent game development learning narrative.", "Review portfolio or project evidence and identify which artifacts are ready to share.", "Define remaining gaps and future specialization priorities."]'::jsonb, '["Summarize completed phases, projects, and major skill groups.", "Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.", "List remaining gaps or specialization topics for future learning.", "State that the checkpoint is a planning review, not proof of job readiness."]'::jsonb),
('required-game-developer-capstone', 'portfolio-and-career-readiness', 'project', NULL, NULL, NULL, 'Required Game Developer Capstone', 'Capstone project brief: Build and publish a polished small game with a clear core loop, menus, audio, save/progress, performance notes, accessibility considerations, and a public project page. Build it as an integrated game prototype for the Game Developer roadmap, with enough scope to connect multiple earlier topics from Portfolio and Career Readiness. Expected evidence includes a playable prototype or isolated mechanic, controls, rules, and tuning notes, and screenshots or a short playtest observation. Keep the implementation reviewable: define the problem, show the working path, validate the result, and document limitations rather than claiming production readiness.', 'This capstone project turns the surrounding Game Developer topics into a concrete artifact. It gives the learner a clearer target, suggested build path, and review evidence without treating completion as proof of mastery or job readiness.', 239, 'choice', 'portfolio-and-career-readiness', 1202, 8, 10, 'intermediate', 12, '{"source": "roadmap.sh/game-developer","parentGroup": "portfolio-and-career-readiness","projectPolicy": "required_milestone","projectPurpose": "capstone","projectKind": "game_project","projectScope": "integrated_multi_topic","evidenceRequired": true,"claimLimit": "reviewable_project_evidence_only_not_mastery_or_job_readiness","suggestedSteps": ["define the core loop or mechanic","build the smallest playable slice","test controls and feedback","record tuning decisions"],"expectedEvidence": ["a playable prototype or isolated mechanic","controls, rules, and tuning notes","screenshots or a short playtest observation"],"optionalPractice": false,"milestone": true,"capstone": true}'::jsonb, true, true, '["Plan and build an integrated Game Developer Capstone that connects multiple topics from the Game Developer roadmap.","Explain the main design, data, tooling, or workflow decisions used in the project.","Validate the project with appropriate evidence such as tests, screenshots, logs, metrics, queries, or review notes.","Document setup, usage, limitations, and at least one follow-up improvement."]'::jsonb, '["A repository, notebook, dashboard, write-up, prototype, or configuration artifact is available for review.","The README or project notes state the project goal, setup steps, usage path, and expected output.","The deliverable includes a playable prototype or isolated mechanic, controls, rules, and tuning notes, and screenshots or a short playtest observation.","The learner records validation evidence such as tests, screenshots, logs, metrics, query results, playtest notes, or manual verification steps.","The review notes identify trade-offs, limitations, and one reasonable next improvement.","The project connects at least three earlier roadmap topics and explains how they interact."]'::jsonb)
;

SELECT m.roadmap_version_id, NULL, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.reason, sn.order_index, sn.layout_role, sn.layout_group, sn.layout_rank, sn.layout_order, sn.estimated_hours, sn.difficulty_level, sn.priority, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria
FROM seed_node sn CROSS JOIN seed_roadmap_map m
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    reason = EXCLUDED.reason,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    layout_group = EXCLUDED.layout_group,
    layout_rank = EXCLUDED.layout_rank,
    layout_order = EXCLUDED.layout_order,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    priority = EXCLUDED.priority,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

UPDATE public.roadmap_node child
SET parent_node_id = parent.roadmap_node_id
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node parent ON parent.roadmap_version_id = m.roadmap_version_id AND parent.slug = sn.parent_key
WHERE child.roadmap_version_id = m.roadmap_version_id
  AND child.slug = sn.node_key
  AND sn.parent_key IS NOT NULL;

UPDATE public.roadmap_node child
SET parent_node_id = NULL
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
WHERE child.roadmap_version_id = m.roadmap_version_id
  AND child.slug = sn.node_key
  AND sn.parent_key IS NULL;

